class Solution {
public:
    string discountPrices(string sentence, int discount) {
        istringstream iss(sentence);
        string word, result;
        while (iss >> word) {
            if (word[0] == '$') {
                int price = stoi(word.substr(1));
                double discountedPrice = price * (1 - (double)discount / 100);
                stringstream ss;
                ss.precision(2);
                ss.fixed;
                ss << "$" << fixed << setprecision(2) << discountedPrice;
                result += ss.str() + " ";
            } else {
                result += word + " ";
            }
        }
        result.pop_back();
        return result;
    }
};
```

